-- One-time sync: push per-store course_image_url (R2 URLs) from local
-- dev to prod for Malaysia, Ghana, Nigeria, Bhutan, and India.
--
-- The R2 bucket is shared between dev and prod, so the URLs are already
-- live; only the per-store EAV pointer rows need to land in prod. We key
-- on SKU so entity_id drift between environments is irrelevant. We write
-- at store_id={2..6} ONLY — SG (store_id=1) and the scope-0 fallback are
-- left untouched so Singapore covers stay exactly as they are.
--
-- Prereq: migration 126 must have run (course_image_url is_global=0).
-- Idempotent: ON DUPLICATE KEY UPDATE rewrites the URL if a different one
-- already exists for that product at that store_id. Safe to re-run.

SET @aid := (SELECT attribute_id FROM eav_attribute WHERE attribute_code='course_image_url' LIMIT 1);

-- store_id=2 (malaysia) — 486 products
INSERT INTO catalog_product_entity_varchar (entity_type_id, attribute_id, store_id, entity_id, value)
SELECT 4, @aid, 2, cpe.entity_id, t.url
FROM catalog_product_entity cpe
JOIN (
  SELECT 'M1001' sku, 'https://pub-77c0dec029944b0386e40673ce81081f.r2.dev/course-covers/M1001-20260523-154615.png' url
  UNION ALL SELECT 'M1002' sku, 'https://pub-77c0dec029944b0386e40673ce81081f.r2.dev/course-covers/M1002-20260523-154616.png' url
