UPDATE catalog_product_flat_5 f
JOIN catalog_product_entity_varchar v
  ON v.entity_id = f.entity_id AND v.attribute_id = @aid AND v.store_id = 5
SET f.course_image_url = v.value
WHERE f.course_image_url IS NULL OR f.course_image_url <> v.value;

